class Solution {
    private Map<Integer, Boolean> memo;

    public boolean canIWin(int maxChoosableInteger, int desiredTotal) {
        if (desiredTotal <= 0) return true;
        if (maxChoosableInteger * (maxChoosableInteger + 1) / 2 < desiredTotal) return false;

        memo = new HashMap<>();
        return dfs(maxChoosableInteger, desiredTotal, 0, 0);
    }

    private boolean dfs(int maxChoosableInteger, int desiredTotal, int used, int currentSum) {
        int key = used * (maxChoosableInteger + 1) + currentSum;
        if (memo.containsKey(key)) return memo.get(key);

        for (int i = 1; i <= maxChoosableInteger; i++) {
            int bit = 1 << (i - 1);
            if ((used & bit) != 0) continue;

            if (currentSum + i >= desiredTotal) {
                memo.put(key, true);
                return true;
            }

            if (!dfs(maxChoosableInteger, desiredTotal, used | bit, currentSum + i)) {
                memo.put(key, true);
                return true;
            }
        }

        memo.put(key, false);
        return false;
    }
}
